// ====== Import unic: Pontaj istoric din bonuri e:Corg (apr 2025-> ), ore = programul magazinului ======
function importPontajIstoric(){
  if(typeof PONTAJ_ISTORIC==='undefined'||!PONTAJ_ISTORIC.length){toast('Nimic de importat');return;}
  var have={}; (DB.pontaj||[]).forEach(function(p){have[p.data+'|'+p.angajat]=1;});
  var willAdd=PONTAJ_ISTORIC.filter(function(x){return !have[x.data+'|'+x.angajat];}).length;
  if(!confirm('Pontaj istoric din bonuri: '+PONTAJ_ISTORIC.length+' zile-angajat.\n'+willAdd+' se adaugă, '+(PONTAJ_ISTORIC.length-willAdd)+' se sar (există deja). Orele = programul magazinului. Backup automat. Continui?'))return;
  try{createBackup('pre-pontaj-istoric-'+todayISO());}catch(e){}
  if(!DB.pontaj)DB.pontaj=[];
  var add=0,skip=0;
  PONTAJ_ISTORIC.forEach(function(x){
    var k=x.data+'|'+x.angajat;
    if(have[k]){skip++;return;} have[k]=1;
    var st=(typeof _bfStore==='function')?_bfStore(x.magId):null;
    var tip=st?st.tip:'Mic'; var prog=(typeof _bfDefProg==='function')?_bfDefProg(tip):'8h/zi L-V';
    var dow=new Date(x.data+'T00:00:00').getDay();
    var h=(typeof _bfDayHours==='function')?_bfDayHours(prog,dow):{s:'9:00',e:'17:00',o:'8'};
    var loc=st?(st.id+' '+st.nume):x.magId;
    DB.pontaj.push({data:x.data,angajat:x.angajat,locatie:loc,tipZi:'Lucrat 🟢',oraStart:h.s,oraSfarsit:h.e,oreLucrate:h.o,observatii:'back-fill bonuri',salvatLa:nowISO(),auto:true,sursaImport:'backfill-receipts'});
    add++;
  });
  save(); try{ if(currentView==='pontaj') go('pontaj'); }catch(e){}
  toast('✓ Pontaj istoric: '+add+' adăugate, '+skip+' sărite.');
}
